package com.trademaster.ims.mobile.payments.service;

import com.trademaster.ims.mobile.auth.service.CustomerAuthException;
import com.trademaster.ims.mobile.checkout.model.*;
import com.trademaster.ims.mobile.checkout.repository.*;
import com.trademaster.ims.mobile.payments.dto.PaymentDtos.*;import com.trademaster.ims.mobile.notifications.service.CustomerNotificationService;
import com.trademaster.ims.mobile.payments.model.*;
import com.trademaster.ims.mobile.payments.model.PaymentMethodConfiguration.MethodType;
import com.trademaster.ims.mobile.payments.repository.*;
import com.trademaster.ims.model.*;
import com.trademaster.ims.repository.*;
import org.springframework.beans.factory.annotation.Autowired;import org.springframework.core.env.Environment;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.math.*;
import java.time.*;
import java.util.*;

@Service
public class MobileWalletPaymentService{
 private static final String METHOD_CODE="MOBILE_WALLET"; private static final String TEST_CODE="123456"; private static final String TEST_PIN="12345";
 private final CustomerOrderRepository orders; private final CustomerOrderStatusHistoryRepository orderHistory; private final PaymentMethodConfigurationRepository methods; private final MobileWalletProviderConfigurationRepository walletProviders; private final CustomerPaymentRepository payments; private final PaymentAttemptRepository attempts; private final PaymentStatusHistoryRepository histories; private final FinancialAccountRepository accounts; private final AccountLedgerEntryRepository ledgers; private final Environment env; @Autowired(required=false) private CustomerNotificationService notifications;
 public MobileWalletPaymentService(CustomerOrderRepository orders,CustomerOrderStatusHistoryRepository orderHistory,PaymentMethodConfigurationRepository methods,MobileWalletProviderConfigurationRepository walletProviders,CustomerPaymentRepository payments,PaymentAttemptRepository attempts,PaymentStatusHistoryRepository histories,FinancialAccountRepository accounts,AccountLedgerEntryRepository ledgers,Environment env){this.orders=orders;this.orderHistory=orderHistory;this.methods=methods;this.walletProviders=walletProviders;this.payments=payments;this.attempts=attempts;this.histories=histories;this.accounts=accounts;this.ledgers=ledgers;this.env=env;}
 @Transactional public List<MobileWalletProviderResponse> providers(long account,String orderNumber){ensureCatalog();CustomerOrder o=owned(account,orderNumber);PaymentMethodConfiguration m=walletMethod();return walletProviders.findByActiveTrueOrderByDisplayOrderAscCodeAsc().stream().map(p->providerDto(p,o,m)).toList();}
 @Transactional public MobileWalletSessionResult initiate(long account,String orderNumber,MobileWalletInitiationRequest q){ensureCatalog();ensureSimulation();CustomerOrder o=orders.lockByOrderNumber(orderNumber).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));own(account,o);PaymentMethodConfiguration m=walletMethod();MobileWalletProviderConfiguration wp=provider(q.providerCode());payable(o,m,wp);PaymentAttempt existing=attempts.findByAccountIdAndOrderIdAndIdempotencyKey(account,o.getId(),q.idempotencyKey()).orElse(null);if(existing!=null)return session(payments.findById(existing.getPaymentId()).orElseThrow(),existing,wp);CustomerPayment p=currentOrNew(o,m,wp);PaymentAttempt a=new PaymentAttempt();a.setPaymentId(p.getId());a.setOrderId(o.getId());a.setAccountId(account);a.setAttemptNumber(attempts.findTopByPaymentIdOrderByAttemptNumberDesc(p.getId()).map(x->x.getAttemptNumber()+1).orElse(1));a.setIdempotencyKey(q.idempotencyKey());a.setMethod(METHOD_CODE);a.setProvider(wp.getCode());a.setAmount(p.getAmount());a.setCurrency(p.getCurrency());a.setStatus(PaymentAttempt.AttemptStatus.SESSION_CREATED);a.setGatewaySessionId("MW-"+LocalDate.now().toString().replace("-","")+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase());a.setExpiresAt(Instant.now().plus(Duration.ofMinutes(10)));attempts.save(a);transition(p,CustomerPayment.PaymentStatus.PENDING_GATEWAY,"MOBILE_WALLET_SESSION","Mobile wallet simulation session created.",PaymentStatusHistory.ActorType.SYSTEM,null);payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.PENDING_GATEWAY);orders.save(o);return session(p,a,wp);}
 @Transactional public PaymentStatusResult confirm(long account,String attemptReference,MobileWalletConfirmRequest q){ensureCatalog();ensureSimulation();PaymentAttempt loaded=attempts.findByGatewaySessionId(attemptReference).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Payment attempt was not found."));if(!Objects.equals(loaded.getAccountId(),account))throw err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Payment attempt was not found.");CustomerPayment p=payments.lockById(loaded.getPaymentId()).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Payment was not found."));CustomerOrder o=orders.lockByOrderNumber(p.getOrderNumber()).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));PaymentAttempt a=attempts.findById(loaded.getId()).orElse(loaded);own(account,o);if(p.getPaymentStatus()==CustomerPayment.PaymentStatus.PAID||a.getStatus()==PaymentAttempt.AttemptStatus.SUCCEEDED)return statusDto(p);if(!METHOD_CODE.equals(a.getMethod()))throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_ELIGIBLE","This attempt is not a mobile wallet attempt.");if(a.getExpiresAt()!=null&&a.getExpiresAt().isBefore(Instant.now())){a.setStatus(PaymentAttempt.AttemptStatus.EXPIRED);attempts.save(a);transition(p,CustomerPayment.PaymentStatus.FAILED,"MOBILE_WALLET_EXPIRED","Mobile wallet session expired. Please start a new payment.",PaymentStatusHistory.ActorType.SYSTEM,null);payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.FAILED);orders.save(o);notifyPaymentFailed(p);return statusDto(p);}MobileWalletProviderConfiguration wp=provider(a.getProvider());String masked=mask(q.walletNumber());a.setExternalReference(masked);if(!validWallet(q.walletNumber())||!TEST_CODE.equals(q.verificationCode())||!TEST_PIN.equals(q.paymentPin())){a.setFailedCredentialAttempts(a.getFailedCredentialAttempts()+1);if(a.getFailedCredentialAttempts()>=3){a.setStatus(PaymentAttempt.AttemptStatus.FAILED);transition(p,CustomerPayment.PaymentStatus.FAILED,"MOBILE_WALLET_CREDENTIALS","Mobile wallet credentials were rejected too many times. Please start again.",PaymentStatusHistory.ActorType.SYSTEM,null);p.setFailureCode("MOBILE_WALLET_CREDENTIALS_INVALID");payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.FAILED);orders.save(o);notifyPaymentFailed(p);}attempts.save(a);throw err(HttpStatus.UNPROCESSABLE_ENTITY,"MOBILE_WALLET_CREDENTIALS_INVALID","Wallet number, verification code, or PIN is invalid for the presentation simulation.");}payable(o,walletMethod(),wp);String result=forcedResult();if("SUCCESS".equals(result)){a.setStatus(PaymentAttempt.AttemptStatus.SUCCEEDED);a.setGatewayTransactionId("MWTX-"+UUID.randomUUID().toString().substring(0,12).toUpperCase());attempts.save(a);p.setGatewayProvider(wp.getCode());p.setGatewayTransactionId(a.getGatewayTransactionId());transition(p,CustomerPayment.PaymentStatus.VERIFIED,"MOBILE_WALLET_SIMULATION","Mobile wallet payment verified in presentation simulation.",PaymentStatusHistory.ActorType.GATEWAY,wp.getCode());postOnce(p,o,"MOBILE_WALLET_"+wp.getCode());transition(p,CustomerPayment.PaymentStatus.PAID,"ACCOUNTING_POSTED","Payment received and posted.",PaymentStatusHistory.ActorType.SYSTEM,null);p.setPaidAt(Instant.now());payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.PAID);o.setAccountingStatus(CustomerOrder.AccountingStatus.POSTED);if(o.getStatus()==CustomerOrder.OrderStatus.PENDING_CONFIRMATION||o.getStatus()==CustomerOrder.OrderStatus.PENDING_PAYMENT){o.setStatus(CustomerOrder.OrderStatus.CONFIRMED);orderStatus(o,"CONFIRMED","Order confirmed after mobile wallet simulation payment.");}orders.save(o);notifyWalletSuccess(p);return statusDto(p);}if("PENDING".equals(result)){a.setStatus(PaymentAttempt.AttemptStatus.PENDING);attempts.save(a);transition(p,CustomerPayment.PaymentStatus.PENDING_GATEWAY,"MOBILE_WALLET_PENDING","Mobile wallet simulation is pending. Refresh to check again.",PaymentStatusHistory.ActorType.GATEWAY,wp.getCode());payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.PENDING_GATEWAY);orders.save(o);return statusDto(p);}if("CANCELLED".equals(result)){a.setStatus(PaymentAttempt.AttemptStatus.CANCELLED);attempts.save(a);transition(p,CustomerPayment.PaymentStatus.CANCELLED,"MOBILE_WALLET_CANCELLED","Mobile wallet simulation was cancelled. The order remains unpaid.",PaymentStatusHistory.ActorType.GATEWAY,wp.getCode());payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.CANCELLED);orders.save(o);notifyPaymentFailed(p);return statusDto(p);}a.setStatus(PaymentAttempt.AttemptStatus.FAILED);attempts.save(a);transition(p,CustomerPayment.PaymentStatus.FAILED,"MOBILE_WALLET_FAILED","Mobile wallet simulation failed. You may retry.",PaymentStatusHistory.ActorType.GATEWAY,wp.getCode());p.setFailureCode("MOBILE_WALLET_FAILED");payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.FAILED);orders.save(o);notifyPaymentFailed(p);return statusDto(p);}
 private void notifyWalletSuccess(CustomerPayment p){if(notifications!=null)notifications.walletSuccess(p.getAccountId(),p.getOrderNumber(),p.getPaymentNumber(),p.getAmount(),p.getGatewayProvider());}
 private void notifyPaymentFailed(CustomerPayment p){if(notifications!=null)notifications.paymentFailed(p.getAccountId(),p.getOrderNumber(),p.getPaymentNumber(),p.getGatewayProvider());}
 private MobileWalletProviderResponse providerDto(MobileWalletProviderConfiguration p,CustomerOrder o,PaymentMethodConfiguration m){boolean eligible=true;String reason=null;try{payable(o,m,p);}catch(CustomerAuthException e){eligible=false;reason=e.getMessage();}return new MobileWalletProviderResponse(p.getCode(),p.getDisplayName(),p.getShortDescription(),eligible,reason,p.getDisplayOrder(),p.getIconAssetKey(),p.getVisualThemeKey(),p.getPhoneLabel(),p.getPhoneHint(),p.isRequiresVerificationCode(),p.isRequiresPaymentPin(),p.getInstructions(),p.getMinAmount(),p.getMaxAmount(),p.getSupportedCurrency());}
 private MobileWalletSessionResult session(CustomerPayment p,PaymentAttempt a,MobileWalletProviderConfiguration wp){return new MobileWalletSessionResult(p.getPaymentNumber(),a.getGatewaySessionId(),p.getOrderNumber(),wp.getCode(),wp.getDisplayName(),p.getAmount(),p.getCurrency(),a.getExpiresAt(),"ENTER_WALLET_NUMBER","Presentation simulation only. Use verification code 123456 and PIN 12345; never enter real wallet credentials.");}
 private CustomerOrder owned(long account,String n){return orders.findByOrderNumberAndAccountId(n,account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));}private void own(long account,CustomerOrder o){if(!Objects.equals(o.getAccountId(),account))throw err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found.");}
 private PaymentMethodConfiguration walletMethod(){return methods.findByCode(METHOD_CODE).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_METHOD_NOT_AVAILABLE","Mobile Wallet is not available."));}private MobileWalletProviderConfiguration provider(String c){return walletProviders.findByCode(c).filter(MobileWalletProviderConfiguration::isActive).orElseThrow(()->err(HttpStatus.NOT_FOUND,"MOBILE_WALLET_PROVIDER_NOT_AVAILABLE","Mobile wallet provider is not available."));}
 private void payable(CustomerOrder o,PaymentMethodConfiguration m,MobileWalletProviderConfiguration p){if(!simulationEnabled()||!p.isSimulationEnabled())throw err(HttpStatus.BAD_REQUEST,"MOBILE_WALLET_SIMULATION_DISABLED","Mobile wallet simulation is not enabled in this environment.");if(!m.isActive())throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_AVAILABLE","Payment method is not available.");if(!"BDT".equalsIgnoreCase(m.getSupportedCurrency())||!"BDT".equalsIgnoreCase(p.getSupportedCurrency()))throw err(HttpStatus.BAD_REQUEST,"PAYMENT_CURRENCY_MISMATCH","Payment currency is not supported.");if(o.getTotal()==null||o.getTotal().compareTo(BigDecimal.ZERO)<=0)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_NOT_AVAILABLE","This order has no payable balance.");if(o.getPaymentStatus()==CustomerOrder.PaymentStatus.PAID)throw err(HttpStatus.CONFLICT,"PAYMENT_ALREADY_PAID","This order is already paid.");if(o.getStatus()==CustomerOrder.OrderStatus.CANCELLED||o.getStatus()==CustomerOrder.OrderStatus.REFUNDED)throw err(HttpStatus.CONFLICT,"PAYMENT_NOT_AVAILABLE","This order is not payable.");BigDecimal total=o.getTotal();if(m.getMinAmount()!=null&&total.compareTo(m.getMinAmount())<0)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_ELIGIBLE","Order total is below method minimum.");if(m.getMaxAmount()!=null&&total.compareTo(m.getMaxAmount())>0)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_ELIGIBLE","Order total is above method maximum.");if(p.getMinAmount()!=null&&total.compareTo(p.getMinAmount())<0)throw err(HttpStatus.BAD_REQUEST,"MOBILE_WALLET_PROVIDER_NOT_ELIGIBLE","Order total is below provider minimum.");if(p.getMaxAmount()!=null&&total.compareTo(p.getMaxAmount())>0)throw err(HttpStatus.BAD_REQUEST,"MOBILE_WALLET_PROVIDER_NOT_ELIGIBLE","Order total is above provider maximum.");}
 private CustomerPayment currentOrNew(CustomerOrder o,PaymentMethodConfiguration m,MobileWalletProviderConfiguration wp){CustomerPayment p=payments.findTopByOrderIdOrderByCreatedAtDesc(o.getId()).filter(x->x.getPaymentStatus()!=CustomerPayment.PaymentStatus.PAID).orElse(null);if(p==null){p=new CustomerPayment();p.setPaymentNumber("TSP-"+LocalDate.now().toString().replace("-","")+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase());p.setOrderId(o.getId());p.setOrderNumber(o.getOrderNumber());p.setAccountId(o.getAccountId());p.setAmount(o.getTotal().setScale(2,RoundingMode.HALF_UP));p.setCurrency("BDT");}p.setMethodCode(METHOD_CODE);p.setMethodType(MethodType.MOBILE_WALLET.name());p.setGatewayProvider(wp.getCode());return payments.save(p);}
 private void transition(CustomerPayment p,CustomerPayment.PaymentStatus next,String source,String note,PaymentStatusHistory.ActorType actor,String ref){CustomerPayment.PaymentStatus prev=p.getPaymentStatus();p.setPaymentStatus(next);if(next==CustomerPayment.PaymentStatus.VERIFIED)p.setVerifiedAt(Instant.now());p.setCustomerVisibleMessage(note);PaymentStatusHistory h=new PaymentStatusHistory();h.setPaymentId(p.getId());h.setPreviousStatus(prev==null?null:prev.name());h.setNewStatus(next.name());h.setSource(source);h.setCustomerVisibleNote(note);h.setActorType(actor);h.setActorReference(ref);histories.save(h);} 
 private void postOnce(CustomerPayment p,CustomerOrder o,String source){if(p.getAccountingStatus()==CustomerPayment.AccountingStatus.POSTED)return;String key="CUSTOMER_PAYMENT:"+p.getPaymentNumber();if(payments.existsByPostingKey(key)){p.setAccountingStatus(CustomerPayment.AccountingStatus.POSTED);return;}FinancialAccount a=accounts.findAll().stream().filter(x->x.getStatus()==FinancialAccount.AccountStatus.ACTIVE).findFirst().orElseThrow(()->err(HttpStatus.CONFLICT,"PAYMENT_POSTING_FAILED","No active posting account is configured."));BigDecimal before=a.getCurrentBalance()==null?BigDecimal.ZERO:a.getCurrentBalance();BigDecimal after=before.add(p.getAmount());a.setCurrentBalance(after);accounts.save(a);AccountLedgerEntry e=new AccountLedgerEntry();e.setAccountId(a.getAccountId());e.setEntryType(AccountLedgerEntry.EntryType.PAYMENT_RECEIPT);e.setDirection(Payment.PaymentDirection.RECEIVE);e.setDebitAmount(p.getAmount());e.setCreditAmount(BigDecimal.ZERO);e.setBalanceBefore(before);e.setBalanceAfter(after);e.setReferenceId(o.getId());e.setVoucherNo(p.getPaymentNumber());e.setDescription("Customer order payment posted: "+o.getOrderNumber()+" via "+source);e.setPostedAt(java.time.LocalDateTime.now());ledgers.save(e);p.setLedgerEntryId(e.getLedgerEntryId());p.setPostingKey(key);p.setPostedAt(Instant.now());p.setAccountingStatus(CustomerPayment.AccountingStatus.POSTED);} 
 private PaymentStatusResult statusDto(CustomerPayment p){List<PaymentAttemptSummary> as=attempts.findByPaymentIdOrderByAttemptNumberAsc(p.getId()).stream().map(a->new PaymentAttemptSummary(a.getAttemptNumber(),a.getStatus().name(),a.getMethod(),a.getProvider(),a.getGatewaySessionId(),a.getExternalReference(),a.getExpiresAt(),a.getCreatedAt())).toList();List<PaymentTimelineEntry> ts=histories.findByPaymentIdOrderByOccurredAtAsc(p.getId()).stream().map(h->new PaymentTimelineEntry(h.getNewStatus(),h.getSource(),h.getCustomerVisibleNote(),h.getOccurredAt(),h.getActorType().name())).toList();boolean retry=p.getPaymentStatus()==CustomerPayment.PaymentStatus.FAILED||p.getPaymentStatus()==CustomerPayment.PaymentStatus.CANCELLED;boolean cancel=p.getPaymentStatus()==CustomerPayment.PaymentStatus.PENDING_GATEWAY;return new PaymentStatusResult(p.getPaymentNumber(),p.getOrderNumber(),p.getPaymentStatus().name(),p.getAccountingStatus().name(),p.getMethodCode(),p.getMethodType(),p.getAmount(),p.getCurrency(),p.getCustomerVisibleMessage(),retry,cancel,as,ts);}
 private void orderStatus(CustomerOrder o,String status,String note){CustomerOrderStatusHistory h=new CustomerOrderStatusHistory();h.setOrderId(o.getId());h.setStatus(status);h.setCustomerNote(note);orderHistory.save(h);} 
 private boolean validWallet(String v){return v!=null&&v.matches("01\\d{9}");}private String mask(String v){if(v==null||v.length()<7)return "***";return v.substring(0,3)+"****"+v.substring(v.length()-4);}private String forcedResult(){String r=env.getProperty("TECHSMART_MOBILE_WALLET_RESULT");if(r==null)r=env.getProperty("techsmart.mobile-wallet.result","SUCCESS");r=r.trim().toUpperCase(Locale.ROOT);return Set.of("SUCCESS","PENDING","FAILED","CANCELLED").contains(r)?r:"SUCCESS";}private boolean simulationEnabled(){boolean prod=Arrays.stream(env.getActiveProfiles()).anyMatch(p->p.equalsIgnoreCase("prod")||p.equalsIgnoreCase("production"));String configured=env.getProperty("TECHSMART_MOBILE_WALLET_SIMULATION");if(configured==null)configured=env.getProperty("techsmart.mobile-wallet.simulation");return !prod&&(configured==null||Boolean.parseBoolean(configured));}private void ensureSimulation(){if(!simulationEnabled())throw err(HttpStatus.BAD_REQUEST,"MOBILE_WALLET_SIMULATION_DISABLED","Mobile wallet simulation is disabled in this environment.");}
 private void ensureCatalog(){ensureMethod();seedProvider("BKASH","bKash","Fast Bangladeshi mobile wallet payment simulation.",1,"wallet_bkash","pink","bKash wallet number","01XXXXXXXXX","Select bKash, enter the presentation wallet number, then use the fixed test code and PIN.");seedProvider("NAGAD","Nagad","Postal-backed digital financial service simulation.",2,"wallet_nagad","orange","Nagad wallet number","01XXXXXXXXX","Select Nagad and complete the presentation-only verification steps.");seedProvider("ROCKET","Rocket","Dutch-Bangla Bank mobile wallet simulation.",3,"wallet_rocket","purple","Rocket wallet number","01XXXXXXXXX","Select Rocket and complete the presentation-only verification steps.");seedProvider("UPAY","Upay","UCB Fintech wallet simulation.",4,"wallet_upay","blue","Upay wallet number","01XXXXXXXXX","Select Upay and complete the presentation-only verification steps.");seedProvider("SURECASH","SureCash","Education and merchant wallet simulation.",5,"wallet_surecash","green","SureCash wallet number","01XXXXXXXXX","Select SureCash and complete the presentation-only verification steps.");seedProvider("TAP","Tap","Trust Axiata Pay wallet simulation.",6,"wallet_tap","teal","Tap wallet number","01XXXXXXXXX","Select Tap and complete the presentation-only verification steps.");}
 private void ensureMethod(){PaymentMethodConfiguration m=methods.findByCode(METHOD_CODE).orElseGet(PaymentMethodConfiguration::new);m.setCode(METHOD_CODE);m.setDisplayName("Mobile Wallet");m.setDescription("Presentation-only Bangladeshi mobile wallet checkout simulation.");m.setType(MethodType.MOBILE_WALLET);m.setProvider("LOCAL_MOBILE_WALLET_SIM");m.setSupportedCurrency("BDT");m.setRequiresReference(false);m.setRequiresProof(false);m.setAutoVerify(true);m.setReviewRequired(false);m.setCustomerInstructions("Choose a wallet provider and complete the local presentation simulation. Do not enter real wallet credentials.");methods.save(m);}private void seedProvider(String c,String n,String d,int order,String icon,String theme,String label,String hint,String instructions){MobileWalletProviderConfiguration p=walletProviders.findByCode(c).orElseGet(MobileWalletProviderConfiguration::new);p.setCode(c);p.setDisplayName(n);p.setShortDescription(d);p.setActive(true);p.setDisplayOrder(order);p.setSimulationEnabled(true);p.setIconAssetKey(icon);p.setVisualThemeKey(theme);p.setPhoneLabel(label);p.setPhoneHint(hint);p.setRequiresVerificationCode(true);p.setRequiresPaymentPin(true);p.setSupportedCurrency("BDT");p.setInstructions(instructions);walletProviders.save(p);}private CustomerAuthException err(HttpStatus s,String c,String m){return new CustomerAuthException(s,c,m);} 
}
